from enum import Enum

class PolicyDecision(Enum):
    PASS = 'pass'
    CONDITIONAL = 'conditional'
    FAIL = 'fail'
    NEEDS_REVIEW = 'needs_review'

# Licence allow/deny configuration (version-controlled, updated quarterly)
ALLOW_LIST = {
    'MIT', 'Apache-2.0', 'BSD-2-Clause', 'BSD-3-Clause',
    'ISC', 'Unlicense', 'CC0-1.0', 'Python-2.0',
}
CONDITIONAL_LIST = {
    'LGPL-2.1-only', 'LGPL-2.1-or-later', 'LGPL-3.0-only', 'LGPL-3.0-or-later',
    'MPL-2.0', 'CDDL-1.0', 'EPL-2.0',
}
DENY_LIST = {
    'GPL-2.0-only', 'GPL-2.0-or-later', 'GPL-3.0-only', 'GPL-3.0-or-later',
    'AGPL-3.0-only', 'AGPL-3.0-or-later', 'SSPL-1.0',
}

def evaluate_policy(result: LicenseScanResult, distribution: str) -> dict:
    """
    Apply the OSS usage policy to a scan result.
    distribution: 'saas' | 'on-prem' | 'embedded'
    """
    if result.needs_manual_review:
        return {
            'decision': PolicyDecision.NEEDS_REVIEW,
            'reason': 'Low confidence detection — manual identification required',
            'action': 'submit_review_ticket',
        }
    spdx = result.detected_spdx
    if spdx in ALLOW_LIST:
        return {'decision': PolicyDecision.PASS, 'reason': 'Permissive licence'}
    if spdx in DENY_LIST:
        # AGPL in SaaS distribution is the highest-risk scenario
        if 'AGPL' in spdx and distribution == 'saas':
            reason = (
                'AGPL network copyleft: source disclosure required for all '
                'users who interact via network API. Proprietary server-side '
                'code must be published. Reject unconditionally for SaaS.'
            )
        else:
            reason = 'Strong copyleft: may contaminate proprietary codebase'
        return {
            'decision': PolicyDecision.FAIL,
            'reason': reason,
            'action': 'block_build_open_legal_ticket',
        }
    if spdx in CONDITIONAL_LIST:
        return {
            'decision': PolicyDecision.CONDITIONAL,
            'reason': 'Weak copyleft: permitted only with dynamic linking',
            'action': 'add_linking_condition_to_sbom',
        }
    return {
        'decision': PolicyDecision.NEEDS_REVIEW,
        'reason': 'SPDX identifier not in any list — escalate to legal',
        'action': 'submit_review_ticket',
    }
